interface CrossFieldRule {
  dependsOn: string[];  // field names this rule depends on
  validate: (value: unknown, context: ValidationContext) => ValidationError | null;
}

interface ValidationContext {
  data: Record<string, unknown>;  // full object being validated
  path: string;                    // current field path
  getFieldValue: (path: string) => unknown;
}

async function validateAsync<T>(
  data: unknown,
  schema: AsyncSchema
): Promise<ValidationResult<T>> {
  const syncErrors = validateSync(data, schema);
  if (syncErrors.length > 0 && schema.abortEarly) {
    return { success: false, errors: syncErrors };
  }

  const asyncResults = await Promise.all(
    schema.asyncValidators.map(v => v.validate(data))
  );

  const allErrors = [...syncErrors, ...asyncResults.filter(Boolean)];
  return allErrors.length === 0
    ? { success: true, data: data as T }
    : { success: false, errors: allErrors };
}
